"""
MKT Original Commentary — Exodus 33–35
Run: python3 scripts/zc-original-exodus-33-35.py

Source data used:
- data/interlinear/exodus.json
- data/translation/draft/mediating/exodus.json

Key decisions in this range:
- Ch33: 'panim el panim' (face to face) contrasted with 'you cannot see my face and live' — treated
  as two distinct modes of encounter: relational intimacy vs. unmediated theophany
- Ch33: 'I will be gracious to whom I will be gracious' (v19) is treated as a statement of
  sovereign freedom, not mere arbitrariness — the standard for election theology
- Ch34:6 already exists; v6 is skipped; vv.7-35 all written
- Ch34: 'qaran' (shone/radiated) is a rare verb — the horns/rays of Moses's face; the same root
  as 'qeren' (horn); deliberately retained as 'radiated' not 'shone with horns'
- Ch34: 'masweh' (veil/mask, v33) — a hapax legomenon; treated as a face-cover, not a full veil
- Ch35: Bezalel's 'ruach Elohim' (Spirit of God) is the first charismatic endowment of a craftsman
  in Scripture; treated as anticipating NT gifts for building the community of God
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS_ORIGINAL = {
    "33": {
        "1": "<p>After the golden calf catastrophe, YHWH commands Israel to depart for Canaan — but without his own presence: <em>wĕšālaḥtî lĕpānêkā malʾāk</em> ('I will send an angel before you'). The angel-substitute for divine presence is the catastrophic downgrade that generates the chapter's central crisis. The land can be inherited without YHWH's presence; that is not the question. Moses understands that a land without YHWH is not worth inheriting.</p>",
        "2": "<p><em>Kĕnaʿănî hāʾĕmōrî wĕhaḥittî</em>: the standard six-nation list of Canaan's inhabitants. The promise of dispossession remains firm even as YHWH withdraws his direct presence. The theological distinction is between covenant guarantee (the land will be yours) and covenantal intimacy (I will dwell among you) — both are part of the Abrahamic promise, but they can be separated. Moses refuses to accept the land without the presence.</p>",
        "3": "<p><em>wĕlōʾ ʾeʿăleh bĕqirbĕkā</em>: 'for I will not go up in your midst.' YHWH's refusal to dwell among Israel is not permanent abandonment but disciplinary withdrawal: <em>pen ʾăkalkĕlĕkā badderek</em> ('lest I destroy you on the way'). The withdrawal protects Israel — YHWH's holy presence among a stiff-necked people is consuming fire. The theology here: the presence of God is simultaneously the most desired gift and the most dangerous reality for sinful people.</p>",
        "4": "<p><em>wayyitʾabbĕlû</em>: 'they mourned.' The people's response to the news of YHWH's withdrawal is lamentation. <em>Wĕlōʾ-šāt ʾîš ʿādyô ʿālāw</em> ('and no one put on his ornaments') — the removal of ornaments is the outward sign of mourning and penitence. The ornamental self-presentation of covenant celebration (the gold used for the calf) is now renounced. The same ornaments that became the calf are now removed as an act of repentance.</p>",
        "5": "<p><em>ʿam qĕšēh ʾōrep ʾattāh</em>: 'you are a stiff-necked people.' The divine diagnosis is repeated from 32:9. <em>Qĕšēh ʾōrep</em> (stiff-necked/hard of neck) — the agricultural image of an ox refusing the yoke of the plowman. The conditional: 'if for a single moment I were to go up in your midst, I would destroy you.' The solution is Moses's intercession, which transforms the condition. The removal of ornaments (<em>wĕhôrēd ʿĕdyô mēʿālāw</em>) in response is the corporate penitential act.</p>",
        "6": "<p><em>wayyitnāṣṣĕlû bĕnê yiśrāʾēl ʾet ʿĕdyām</em>: 'the children of Israel stripped themselves of their ornaments.' The stripping is permanent from Mount Horeb onward — <em>min har ḥōreb wāhālĕʾāh</em>. The gold ornaments of Egypt (12:35-36) were the material of the golden calf; now permanently renounced, they become the material of the tabernacle donation (35:22). The same wealth that funded idolatry is redirected to YHWH's dwelling — the transformation of the people's material lives parallels the transformation of the covenant relationship.</p>",
        "7": "<p><em>wĕʾōhel nāṭāh lô miḥûṣ lammaḥăneh hārḥēq min-hammaḥăneh</em>: 'he pitched a tent outside the camp, far from the camp.' The tent of meeting is relocated outside the camp in the aftermath of the golden calf — YHWH's withdrawal is geographically enacted. This is the proto-tabernacle, functioning before the construction of the actual tabernacle. <em>Wĕhāyāh kol-mĕbaqqēš YHWH yēṣēʾ ʾel-ʾōhel môʿēd ʾăšer miḥûṣ lammaḥăneh</em>: 'everyone who sought YHWH went out to the tent of meeting.' Seeking God requires going outside the camp — the outside positioning is not merely geographic but theological: holiness stands at a distance from the contaminated community.</p>",
        "8": "<p>When Moses went out to the tent, all the people rose and stood, each at his tent door, watching Moses until he entered. The communal watching (<em>hibbîṭû ʾaḥărê mōšeh</em>) is reverent observation of the mediator approaching the divine presence. The posture — everyone at their own tent door — simultaneously represents the community's solidarity with Moses and their inability to approach themselves. They can only watch the mediator enter what they cannot enter.</p>",
        "9": "<p><em>wĕhāyāh kĕbōʾ mōšeh hāʾōhĕlāh yērēd ʿammûd heʿānān wĕʿāmad petaḥ hāʾōhel</em>: 'when Moses entered the tent, the pillar of cloud descended and stood at the entrance of the tent.' The cloud pillar — YHWH's theophanic presence — settles at the entrance: YHWH meets Moses at the threshold but does not enter in full. The contrast with 40:34 (when the cloud fills the completed tabernacle) is significant — here the presence is partial, transitional, anticipating the full Shekinah indwelling when the covenant is restored.</p>",
        "10": "<p>All the people saw the cloud pillar standing at the tent entrance and <em>qāmû kol-hāʿām wĕhištaḥăwû ʾîš petaḥ ʾōhĕlô</em>: 'all the people rose and bowed down, each at his own tent door.' The corporate worship from the distance of their tent doors mirrors the later arrangement of the court and sanctuary: the people worship from the outer court while the priest enters the inner sanctuary. The spatial arrangement of wilderness worship anticipates the tabernacle's graduated holiness.</p>",
        "11": "<p><em>wĕdibbēr YHWH ʾel-mōšeh pānîm ʾel pānîm kaʾăšer yĕdabbēr ʾîš ʾel rēʿēhû</em>: 'YHWH spoke to Moses face to face as a man speaks to his friend.' The intimacy formula — face to face as a friend speaks — is the highest description of prophetic access in the Torah (Num 12:8: 'face to face I speak with him, plainly and not in riddles'). Yet v.20 declares Moses cannot see YHWH's face and live. The two statements are not contradictory: 'face to face' describes the relational directness and intimacy of the communication; the ban on seeing YHWH's face describes the impossibility of unmediated encounter with the full divine glory.</p>",
        "12": "<p>Moses argues with YHWH on the basis of personal knowledge: 'you have said to me, you know you by name, and you have found favor in my sight.' The verb <em>yādaʿtîkā bĕšēm</em> (knowing by name) indicates covenantal identification — YHWH knows Moses as an individual, not merely as a functionary. Moses leverages this personal knowledge in intercession: 'If I have found favor in your sight, please show me now your ways.' The intercession builds argument from already-granted grace.</p>",
        "13": "<p><em>wĕhôdîʿēnî nā ʾet-dĕrākêkā</em>: 'please make me know your ways.' The request is epistemological: Moses wants to know YHWH's character and method of dealing — not merely his commands but his nature. The <em>nā</em> (please/I pray) is the particle of urgent request. The justification: <em>lĕmaʿan ʾedāʿăkā lĕmaʿan ʾemṣāʾ ḥēn bĕʿênêkā</em> — 'so that I may know you, so that I may find favor in your eyes.' Knowledge of YHWH and favor with YHWH are inseparable — to know him is to be known by him.</p>",
        "14": "<p><em>pānay yēlēkû wăhăniḥōtî lāk</em>: 'My face will go, and I will give you rest.' YHWH's response is a renewed covenant of presence. <em>Pānay</em> (my face/my presence) is the theological term for YHWH's manifest presence accompanying his people — the same root as <em>pānîm ʾel pānîm</em> of v.11. The promise <em>hăniḥōtî lāk</em> ('I will give you rest') combines the land-promise (settled rest from enemies) with the presence-promise (YHWH accompanying and sheltering). Moses takes this as YHWH personally going with Israel, not sending a substitute.</p>",
        "15": "<p><em>ʾim ʾên pānêkā hōlēkîm ʾal taʿălēnû mizzeh</em>: 'if your face/presence does not go with us, do not bring us up from here.' Moses's ultimatum: the land without YHWH's presence is not worth having. This is one of the OT's strongest statements of the theology of divine presence as the supreme covenant blessing. The land, wealth, and victory are secondary goods; YHWH himself is the primary good. Moses refuses the gift without the Giver.</p>",
        "16": "<p><em>ûbammeh yiwwādaʿ ʾēpôʾ kî-māṣātî ḥēn bĕʿênêkā ʾănî wĕʿammekā hălôʾ bĕlektĕkā ʿimmānû wĕnipalînu ʾănî wĕʿammĕkā mikkol-hāʿām ʾăšer ʿal-pĕnê hāʾădāmāh</em>: 'how will it be known that I have found favor in your eyes, I and your people, if you do not go with us? It is by your going with us that we and your people will be distinct from every people on the face of the earth.' The distinguishing mark of Israel is not ethnicity, law, or land — it is the presence of YHWH. <em>Wĕnipalînu</em> (we will be set apart/distinguished, Niphal of <em>pālāh</em>) — the same root as in the plagues, where YHWH set Israel apart from Egypt. Divine presence is the identity-constituting reality for the covenant community.</p>",
        "17": "<p>YHWH grants Moses's intercession: <em>gam ʾet-haddābār hazzeh ʾăšer dibbartā ʾeʿĕśeh</em> — 'this very thing that you have spoken I will do.' The intercessor's prayer is answered in full. The basis: <em>kî māṣātā ḥēn bĕʿênay wāʾēdāʿăkā bĕšēm</em> — 'for you have found favor in my eyes and I know you by name.' The same arguments Moses used in intercession are now YHWH's stated reasons for granting the intercession. The prayer was effective precisely because it was grounded in YHWH's own prior grace.</p>",
        "18": "<p><em>harʾēnî nāʾ ʾet-kĕbōdekā</em>: 'Please show me your glory.' Moses's request escalates: having secured YHWH's presence with Israel, he now asks for unmediated vision of the divine glory itself. <em>Kābôd</em> (glory/weightiness) is the full manifestation of YHWH's being — what appeared in the cloud and fire (16:10; 24:16-17) is what Moses now asks to see directly. The request tests the limits of human capacity for divine encounter — a test that v.20 will answer with the gracious accommodation of the cleft.</p>",
        "19": "<p><em>ʾănî ʾaʿăbîr kol-ṭûbî ʿal-pānêkā wĕqārāʾtî bĕšēm YHWH lĕpānêkā wĕḥannōtî ʾet-ʾăšer ʾāḥōn wĕriḥamtî ʾet-ʾăšer ʾăraḥēm</em>: 'I will make all my goodness pass before your face, and I will proclaim the name of YHWH before you. And I will be gracious to whom I will be gracious, and I will show mercy on whom I will show mercy.' The double Qal imperfect of the cognate verb construction — <em>ḥannōtî ʾet-ʾăšer ʾāḥōn</em> (I will be gracious to whom I will be gracious) — declares YHWH's sovereign freedom in extending grace. Paul quotes this verse in Rom 9:15-16 to establish the doctrine of unconditional election: grace does not respond to prior human merit but to divine will. The <em>ṭûb</em> (goodness) of YHWH — his full moral character — is what will be displayed, not his unmediated face.</p>",
        "20": "<p><em>lōʾ tûkal lirʾōt ʾet-pānay kî lōʾ-yirʾanî hāʾādām waḥāy</em>: 'You cannot see my face, for man cannot see me and live.' The ban on seeing YHWH's face (<em>pānay</em>) is absolute — no human being can survive the unmediated encounter with the divine glory. The word <em>hāʾādām</em> (man, the human) is generic: not Moses specifically but any human being. The limitation is not a judgment on Moses's character but a statement about the ontological gap between finite creature and infinite Creator. The cleft provision (v.22) is YHWH's gracious accommodation to this ontological limit.</p>",
        "21": "<p><em>hinnēh māqôm ʾittî wĕnīṣabtā ʿal-haṣṣûr</em>: 'Behold, there is a place by me, and you shall stand on the rock.' The phrase <em>māqôm ʾittî</em> (a place by me/with me) is the spatial accommodation YHWH provides for Moses. The same word <em>māqôm</em> (place) will be applied to sacred sites throughout the OT (Gen 28:17: 'this is the gate of heaven'). The rock (<em>haṣṣûr</em>) is the hiding and protection place that mediates the encounter — related to the rock of 17:6 where YHWH stood to be struck.</p>",
        "22": "<p><em>wĕhāyāh baʿăbōr kĕbōdî wĕśamtîkā bĕniqrat haṣṣûr wĕśakkōtî kappî ʿālêkā ʿad ʿăbōrî</em>: 'when my glory passes by, I will put you in a cleft of the rock, and I will cover you with my hand until I have passed by.' Three elements: the cleft (<em>niqrat haṣṣûr</em> — the hollow/cleft of the rock), the hand covering (<em>kappî</em> = my palm), and the passage (<em>ʿad ʿăbōrî</em> = until I pass). Moses is hidden, covered, and sheltered from the full blast of YHWH's glory. The rock cleft as the shelter for the divine encounter becomes a paradigm of the grace that protects the creature from consuming divine holiness.</p>",
        "23": "<p><em>wahăsirōtî ʾet kappî wĕrāʾîtā ʾet ʾăḥōrāy ûpānay lōʾ yērāʾû</em>: 'Then I will take away my hand, and you shall see my back (<em>ʾăḥōrāy</em>), but my face shall not be seen.' The sequence: YHWH passes, the hand is removed, Moses sees <em>ʾăḥōrāy</em> (my back/afterglow/aftermath). The word <em>ʾāḥôr</em> (back/rear) may indicate the retreating glory — what remains after the direct encounter, the aftereffect of divine presence rather than its full face. This 'backglow' is sufficient to illuminate Moses's face (34:29). The contrast is maximal: no one can see the face; even this partial vision is sufficient to transform the prophet.</p>"
    },
    "34": {
        "1": "<p><em>pesol lĕkā šĕnê lûḥōt ʾăbānîm kāriʾšōnîm</em>: 'Cut for yourself two tablets of stone like the first ones.' The new tablets require Moses's own labor (<em>pesol lĕkā</em> = cut for yourself) — unlike the first tablets, which were entirely YHWH's work (32:16: 'the work of God'). The writing is still YHWH's (<em>wĕkātabtî ʾal-halûḥōt</em> = I will write on the tablets), but the preparation of the material is now Moses's task. This shift in the covenant renewal: the second covenant involves human participation in preparation even while the content remains divine.</p>",
        "2": "<p>Moses is commanded to be ready in the morning (<em>wĕhāyîtā nākôn labbōqer</em>) and come up to Mount Sinai. The morning ascent pattern — the same time when the manna was gathered and the Sabbath morning designated for rest — carries the rhythm of covenant renewal into the liturgical cycle. Moses ascends alone (<em>wĕʾîš lōʾ yiʿăleh ʿimmāk</em>); the covenant renewal is a private encounter before its public declaration.</p>",
        "3": "<p><em>wĕʾîš lōʾ-yirʾeh bĕkol-hāhār gam-haṣṣōʾn wĕhabbāqār ʾal-yirʿû ʾel-mûl hāhār hahûʾ</em>: 'no one shall appear in all the mountain; neither flocks nor herds shall graze before that mountain.' The comprehensive exclusion — no human, no animal — recreates the holiness boundary of the original Sinai theophany (19:12-13). The renewal demands the same awe as the original institution. The covenant is not a casual recondition; it requires the full formal apparatus of holy encounter.</p>",
        "4": "<p>Moses cuts the two tablets, rises early in the morning, and ascends Sinai with the two tablets in hand (<em>bĕyādô</em>). The combination of obedience (cuts as commanded, rises early) and preparation (brings the tablets) enacts Moses as the faithful mediator. His actions model the covenant response: doing exactly as YHWH commanded, without delay or modification.</p>",
        "5": "<p><em>wayyērēd YHWH beʿānān wayyityaṣṣēb ʿimmô šām wayyiqrāʾ bĕšēm YHWH</em>: 'YHWH descended in the cloud and stood with him there, and proclaimed the name of YHWH.' The cloud descent is the theophanic vehicle; the proclamation of the divine name is the content. The phrase <em>wayyiqrāʾ bĕšēm YHWH</em> is ambiguous — it could be YHWH proclaiming his own name, or Moses calling on YHWH's name. The context favors YHWH's self-proclamation: what follows in v.6 is the definitive self-disclosure of the divine character.</p>",
        "7": "<p><em>nōṣēr ḥesed lāʾlāpîm nōśēʾ ʿāwōn wāpeša wĕḥaṭṭāʾāh wĕnaqqēh lōʾ yĕnaqqeh pōqēd ʿăwōn ʾābōt ʿal-bānîm</em>: 'keeping steadfast love for thousands, bearing iniquity and transgression and sin, and by no means clearing the guilty, visiting the iniquity of the fathers on the children to the third and fourth generation.' The asymmetry is deliberate and theologically crucial: mercy extends to thousands (<em>lāʾlāpîm</em> = to the thousandth generation), but punishment only to the third and fourth generation. The three sin-terms — <em>ʿāwōn</em> (iniquity, moral distortion), <em>peša</em> (transgression, rebellion), <em>ḥaṭṭāʾāh</em> (sin, missing the mark) — together cover the full spectrum of human wrongdoing. YHWH does not simply set aside guilt (<em>wĕnaqqēh lōʾ yĕnaqqeh</em> = 'by no means clearing/acquitting') — this tension between mercy and justice reaches its resolution only in the atonement.</p>",
        "8": "<p>Moses immediately bows and worships (<em>wayyiqqōd mōšeh ʾarṣāh wayyištaḥû</em>). The response to the proclamation of the divine character is prostration — the knowledge of YHWH's mercy and holiness together produces not familiarity but awe. The thirteen attributes (vv.6-7) are not abstract propositions but the living character of the God before whom Moses falls.</p>",
        "9": "<p>Moses intercedes immediately: if I have found favor, let YHWH go in Israel's midst, even though they are stiff-necked (<em>ʿam qĕšēh ʾōrep</em>). The appeal is to the very mercy just proclaimed: YHWH has declared himself forgiving of iniquity and transgression — Moses calls YHWH to act in accordance with his own character. <em>Wĕsālaḥtā lăʿăwōnēnû ûlĕḥaṭṭāʾtēnû ûnĕḥaltānû</em>: 'forgive our iniquity and sin and take us for your inheritance.' The three petitions correspond to the three sin-terms of v.7 — Moses is asking YHWH to exercise toward Israel exactly the mercy he has just claimed as his character.</p>",
        "10": "<p><em>hinnēh ʾānōkî kōrēt bĕrît</em>: 'Behold, I am making a covenant.' YHWH responds to Moses's intercession with covenant renewal. The covenant is not a renegotiated form but the same covenant on new tablets — the content of YHWH's commitment is unchanged; the relationship is restored. <em>Niplāʾōt ʾăšer lōʾ-nibĕrĕʾû bĕkol-hāʾāreṣ</em>: 'wonders that have not been created in all the earth' — the renewed covenant is accompanied by miraculous signs that distinguish Israel from all other nations. The covenant is the source of Israel's unique history.</p>",
        "11": "<p>The covenant stipulations begin with expulsion of the Canaanite nations. <em>Šĕmor lĕkā ʾēt ʾăšer ʾānōkî mĕṣawwĕkā hayyôm</em>: 'Observe what I command you today.' The renewed covenant has the same stipulation structure as the original: grace, then obligation. YHWH will drive out the nations; Israel must not make covenants with them or intermarry. The covenant relationship demands exclusive allegiance.</p>",
        "12": "<p><em>hišāmer lĕkā pen-tikkĕrōt bĕrît lĕyôšēb hāʾāreṣ</em>: 'Take care, lest you make a covenant with the inhabitants of the land.' The danger of covenant entanglement with Canaan is the specific warning: their altars must be torn down, their pillars broken, their Asherah poles cut down. The exclusivity of the covenant with YHWH requires the destruction of all alternatives — not toleration, not negotiation, but dismantling.</p>",
        "13": "<p><em>mīzbĕḥōtēhem tiṯṯōṣûn ûmaṣṣĕbōtām tĕšabbērûn wĕʾăšērāw tikrōtûn</em>: three verbs of destruction targeting three types of pagan installation: altars (<em>mīzbĕḥōt</em>), sacred pillars (<em>maṣṣĕbôt</em>), and Asherah poles (<em>ʾăšērîm</em>). Each type targets a different aspect of Canaanite worship: the altar (sacrifice site), the standing stone (deity's presence marker), the wooden pole (fertility goddess symbol). The comprehensive dismantling leaves no residue of alternative worship systems.</p>",
        "14": "<p><em>kî YHWH qannāʾ šĕmô ʾēl qannāʾ hûʾ</em>: 'For YHWH, whose name is Jealous (<em>qannāʾ</em>), is a jealous God.' The divine name 'Jealous' appears only here and in 20:5. <em>Qannāʾ</em> (from <em>qānāʾ</em>, to be jealous/zealous) describes YHWH's passionate, exclusive claim on Israel's allegiance — the covenantal love that cannot tolerate a rival. The use of <em>qannāʾ</em> as a divine name (not merely an attribute) indicates this is constitutive of who YHWH is, not a mood he occasionally enters. NT application: Christ claims the same exclusivity ('no one comes to the Father except through me,' John 14:6).</p>",
        "15": "<p>The specific danger of covenant with Canaanite peoples: they will invite Israel to eat their sacrifices, and Israel's sons will take their daughters as wives. The warning traces the path of apostasy: shared meals at pagan altars → intermarriage → idolatry through the spouse's influence. The same concern appears in Solomon's apostasy (1 Kgs 11:1-13) and the Ezra-Nehemiah crisis (Ezra 9-10) — the historical record validates the prophylactic warning.</p>",
        "16": "<p><em>wĕlāqaḥtā mibĕnōtāw lĕbānêkā wĕzānû bĕnōtāw ʾaḥărê ʾĕlōhêhen wĕhiznû ʾet-bānêkā ʾaḥărê ʾĕlōhêhen</em>: 'and when you take their daughters for your sons, and their daughters prostitute themselves after their gods, they will make your sons prostitute themselves after their gods.' The verb <em>zānāh</em> (to prostitute/play the harlot) applied to apostasy is the dominant metaphor of Hosea, Jeremiah, and Ezekiel — Israel's covenant relationship with YHWH is a marriage, so other-god worship is adultery.</p>",
        "17": "<p><em>ʾĕlōhê massēkāh lōʾ taʿăśeh lāk</em>: 'You shall not make cast idols for yourself.' The prohibition directly references the golden calf incident (<em>massēkāh</em> = cast/poured metal image, the same word used in 32:4). The renewed covenant is a covenant for a people who have already violated this command and been forgiven — the repetition is a reminder in the context of grace, not merely legal reiteration.</p>",
        "18": "<p>The Festival of Unleavened Bread (<em>ḥag hammaṣṣôt</em>) and its seven-day observance in the month of Abib. The calendar of Israel's worship is embedded in the covenant renewal: the festivals that commemorate YHWH's saving acts are part of the covenant stipulations. <em>ʾĕt ḥōdeš hāʾābîb</em> (in the month of Abib — the spring month of the Exodus) — the Passover month anchors the entire liturgical year in the formative redemptive event.</p>",
        "19": "<p>The firstborn law: all that opens the womb belongs to YHWH. The principle of consecration of first fruits — the first of everything belongs to the One who gives everything — applies to livestock as well as people. <em>Bekôr</em> (firstborn) is the theological category established in the Exodus itself: YHWH struck Egypt's firstborn to redeem Israel his firstborn son (4:22-23; 11:5; 13:2).</p>",
        "20": "<p>The firstborn donkey redeemed with a lamb; if not redeemed, its neck is broken. The human firstborn must be redeemed. <em>Wĕlōʾ-yērāʾû pānay rêqām</em>: 'and they shall not appear before me empty-handed.' The covenant community comes before YHWH bringing something — the firstfruits that acknowledge his ownership. Appearing empty-handed (without offering) is the refusal to acknowledge covenant relationship. The offering is not earning favor but expressing dependence.</p>",
        "21": "<p><em>šēšet yāmîm taʿăbōd ûbayyôm haššĕbîʿî tišbōt bĕḥāriš ûbaqāṣîr tišbōt</em>: 'Six days you shall work, but on the seventh day you shall rest; in plowing time and in harvest you shall rest.' The Sabbath law includes the most demanding seasons of agricultural labor — plowing and harvest. The Sabbath is not a convenience but a challenge: rest even when work is most urgent, trusting YHWH's provision over human effort. The sabbatical principle reshapes the agricultural economy around covenant time rather than production demand.</p>",
        "22": "<p>Three harvest festivals: <em>ḥag šābuʿōt</em> (Festival of Weeks, seven weeks after Passover = Pentecost), <em>ḥag hāʾāsîp</em> (Festival of Ingathering = Tabernacles), and the transition of the year (<em>tĕqûpat haššānāh</em>). The three pilgrimage festivals structure Israel's entire agricultural year as a series of appearances before YHWH. The calendar of Israel is not merely a timekeeping system but a theology of providence — each harvest is a gift to be acknowledged before the Giver.</p>",
        "23": "<p>Three times a year all males shall appear before YHWH, the God of Israel. The pilgrimage obligation — leaving home, going to the sanctuary — is the embodied enactment of covenant priority. YHWH is called <em>hāʾādôn YHWH ʾĕlōhê yiśrāʾēl</em> (the Lord YHWH God of Israel) — the full covenant identification. The triannual appearance is the covenant community's repeated acknowledgment of who their Lord is.</p>",
        "24": "<p>The promise accompanying the pilgrimage obligation: YHWH will drive out the nations before Israel and enlarge its territory. The vulnerability of pilgrimage — the land unattended while everyone goes to the sanctuary — is met with a divine security guarantee: <em>wĕlōʾ yaḥmod ʾîš ʾet-ʾarṣĕkā bĕʿālōtĕkā</em> ('no one shall covet your land when you go up'). YHWH's provision during human absence is the structural expression of covenant trust: appearing before YHWH creates the condition for YHWH to protect what is entrusted to him.</p>",
        "25": "<p><em>lōʾ-tišḥaṭ ʿal-ḥāmēṣ dam zibḥî</em>: 'You shall not offer the blood of my sacrifice with leaven.' The purity requirements for sacrifice: no leaven mixed with the blood offering (cf. 12:15-20 — leaven is excluded from Passover). The separation of the sacred from ordinary bread (leaven is part of daily life) maintains the distinctiveness of covenant worship. The same principle of separation underlies the NT's 'purge out the old leaven' (1 Cor 5:7-8).</p>",
        "26": "<p>The first of the firstfruits of the ground shall be brought to the house of YHWH. <em>Lōʾ tĕbaššēl gĕdî baḥălēb ʾimmô</em>: 'You shall not boil a young goat in its mother's milk.' The prohibition — which appears three times (13:19; 23:19; here) — protects against the use of the mother's milk (which is for sustaining life) as the medium of the offspring's death. It may also distinguish Israelite practice from Canaanite sacrificial customs. The triple repetition in the Torah signals its importance for covenant identity.</p>",
        "27": "<p><em>kĕtāb lĕkā ʾet-hadĕbārîm hāʾēlleh kî ʿal-pî hadĕbārîm hāʾēlleh kāraʾtî ʾittĕkā bĕrît wĕʾet-yiśrāʾēl</em>: 'Write these words, for in accordance with these words I have made a covenant with you and with Israel.' YHWH commands Moses to write — the covenant is a written document, not merely oral tradition. The written word is the enduring form of the covenant. The parallel to the Sinai tablets: YHWH wrote on stone, Moses writes these words; the covenant has both divine inscription and human transcription.</p>",
        "28": "<p><em>wayhî šām ʿim YHWH ʾarbāʿîm yôm wĕʾarbāʿîm laylāh leḥem lōʾ ʾākal ûmayim lōʾ šātāh</em>: 'He was there with YHWH forty days and forty nights; he neither ate bread nor drank water.' The second forty-day fast mirrors the first (24:18) — both covenant encounters require the same duration of concentrated divine presence. The abstention from food and water is not ascetic virtue but the physical sign of being entirely sustained by the divine presence. Jesus's forty-day fast in the wilderness (Matt 4:2) recapitulates Moses's Sinai fasts — the new covenant mediator undergoes the same probationary discipline as the old.</p>",
        "29": "<p><em>wĕlōʾ yādaʿ mōšeh kî qāran ʿôr pĕnê mōšeh bĕdabbĕrô ʾittô</em>: 'Moses did not know that the skin of his face shone (<em>qāran</em>) because he had been speaking with him.' The verb <em>qāran</em> (to emit rays, to shine) derives from <em>qeren</em> (horn/ray) — Moses's face emitted rays of light after the divine encounter. The unconscious nature of the transformation (<em>lōʾ yādaʿ</em>) is significant: the glory is not Moses's achievement but an effect of contact with YHWH's presence. Paul's extended meditation on this verse in 2 Cor 3:7-18 contrasts the fading glory (the veil hides what is passing away) with the permanent, unveiled glory of the new covenant.</p>",
        "30": "<p>Aaron and all the children of Israel saw Moses: <em>wĕhinnēh qāran ʿôr pānāyw wayyîrĕʾû miggešet ʾēlāyw</em> — 'his face was shining, and they were afraid to come near him.' The radiance creates a distance — the reflected glory makes Moses approachable only with preparation. The fear response is the human reaction to mediated divine holiness: even the derivative glory (Moses reflecting YHWH's glory) is beyond ordinary human comfort.</p>",
        "31": "<p>Moses calls Aaron and the leaders, and they return to him. He gives them the commandments just received. The structured order of proclamation — leaders first, then the whole community — establishes the pattern of covenant transmission: from the mediator to the elders to the people. The same pattern governs the delivery of the law throughout Deuteronomy.</p>",
        "32": "<p>After that, all the children of Israel approach and Moses commands them all that YHWH had spoken with him on Sinai. The completeness of transmission is emphasized: Moses passes on everything, not a selection. <em>Kol ʾăšer dibbēr YHWH ʾittô bĕhar Sînāy</em> — 'all that YHWH had spoken with him on Mount Sinai.' The chain of revelation: YHWH → Moses → leaders → people. Each link transmits without loss.</p>",
        "33": "<p><em>ûkĕkallōt mōšeh lĕdabbēr ʾittām nātan ʿal-pānāyw masweh</em>: 'when Moses had finished speaking with them, he put a veil (<em>masweh</em>) on his face.' The word <em>masweh</em> (veil/covering) is a hapax legomenon in the OT — this is its only occurrence. The veil is put on after the speaking, not before — during proclamation Moses is unveiled, but between sessions of covenant instruction his face is covered. Paul's reading of the veil in 2 Cor 3:13-18 interprets it as hiding the fading glory; but textually, it also protects the people from the unmediated radiance that frightened them (v.30).</p>",
        "34": "<p><em>ûbĕbōʾ mōšeh lipnê YHWH lĕdabbēr ʾittô yāsîr ʾet-hammasweh ʿad ṣēʾtô</em>: 'when Moses went in before YHWH to speak with him, he took off the veil until he came out.' The veil protocol: Moses removes it when entering YHWH's presence (face-to-face access to the divine), keeps it on when among the people between instruction sessions. The veil marks the boundary between the two registers of Moses's existence — priestly access to YHWH and mediatorial communication to Israel.</p>",
        "35": "<p><em>wĕrāʾû bĕnê yiśrāʾēl ʾet-pĕnê mōšeh kî qāran ʿôr pĕnê mōšeh</em>: 'the children of Israel saw the face of Moses, that the skin of Moses's face shone.' The pattern repeats each time Moses emerges from the divine presence — the shining is renewed with each encounter. The glory is not permanent on Moses; it requires repeated visits. Paul's contrast: the new covenant's glory is <em>doxa ek doxes</em>, glory from glory, permanently transforming (2 Cor 3:18: 'beholding the glory of the Lord, we are being transformed into the same image from one degree of glory to another').</p>"
    },
    "35": {
        "1": "<p><em>ʾēlleh hadĕbārîm ʾăšer-ṣiwwāh YHWH laʿăśōt ʾōtām</em>: 'These are the words that YHWH has commanded you to do.' Moses assembles the whole congregation to receive the tabernacle instructions. The phrase <em>kol-ʿădat bĕnê yiśrāʾēl</em> (the whole congregation of the children of Israel) emphasizes the communal nature of the project — the tabernacle is Israel's collective act of worship, not Moses's or the craftsmen's alone.</p>",
        "2": "<p><em>šēšet yāmîm tēʿāśeh mĕlāʾkāh ûbayyôm haššĕbîʿî yihyeh lākem qōdeš šabbat šabbātôn laYHWH</em>: 'Six days work shall be done, but the seventh day shall be for you holy, a Sabbath of complete rest to YHWH.' The Sabbath command is placed before the tabernacle construction instructions — even the holy work of building YHWH's dwelling is subordinate to the Sabbath. No project, however sacred, overrides the covenant rhythm of rest. The placement signals that the Sabbath is more fundamental than the sanctuary.</p>",
        "3": "<p><em>lōʾ tĕbaʿărû ʾēš bĕkōl mōšĕbōtêkem bĕyôm haššabbāt</em>: 'You shall not kindle fire in any of your dwelling places on the Sabbath day.' The specific prohibition against fire on the Sabbath — appearing only here in the Torah — may address the smelting and casting involved in tabernacle metalwork. The Sabbath boundary holds even in the productive fire of construction. The Mishnah later derives 39 categories of prohibited Sabbath labor from the 39 types of work performed in building the tabernacle.</p>",
        "4": "<p><em>zeh hadĕbār ʾăšer ṣiwwāh YHWH lēʾmōr</em>: 'This is the thing that YHWH has commanded.' The transition from the Sabbath prohibition to the freewill offering collection. The connection is significant: the offering is described as divinely commanded, not self-initiated by the people — YHWH commands the freewill offering, which means the freedom and the command are not opposed. Commanded generosity is still real generosity.</p>",
        "5": "<p><em>qĕḥû mēʾittĕkem tĕrûmāh laYHWH kōl nĕdîb libbô yĕbiʾehā ʾēt tĕrûmat YHWH</em>: 'Take from among you a contribution to YHWH. Whoever is of a generous heart (<em>kol nĕdîb libbô</em>), let him bring YHWH's contribution.' The contribution (<em>tĕrûmāh</em>, literally 'a lifting up/heave offering') is described by the quality of the giver: <em>nĕdîb lēb</em> (generous/willing heart). The motivation is internal disposition, not external compulsion. The freewill offering theology: the tabernacle is built not by taxation but by the willing generosity of those who have encountered YHWH's grace.</p>",
        "6": "<p>The materials list begins: gold, silver, bronze; blue, purple, and scarlet yarns; fine twisted linen; goats' hair. These are the same materials specified in Exod 25:3-7 — the instructions given on Sinai are now being gathered from the community. The list moves from precious metals to textiles, establishing the hierarchy of value that will be reflected in the graduated holiness of the tabernacle's zones.</p>",
        "7": "<p>The list continues: acacia wood, oil for the lamp, spices for the anointing oil and for fragrant incense, onyx stones, and stones for setting in the ephod and breastpiece. The comprehensive list covers everything needed for the completed tabernacle. The anointing oil and incense are specialized — requiring expert preparation (30:22-38). The gem-setting requires the craftsman's skill. The community's offering covers both raw materials and specialized items.</p>",
        "8": "<p><em>wĕkōl ḥăkam-lēb bākem yābōʾû wĕyaʿăśû ʾēt kol-ʾăšer ṣiwwāh YHWH</em>: 'and every skillful person among you shall come and make all that YHWH has commanded.' The skill component: <em>ḥăkam-lēb</em> (wise/skilled of heart) — the craftsman's competence is a matter of the heart, not merely technical training. Wisdom in Hebrew encompasses practical skill as well as moral insight; the skilled craftsman exercises the same faculty as the wise ruler or the discerning judge.</p>",
        "9": "<p>The list of structures to be made: the tabernacle and its tent, covering, clasps, frames, bars, pillars, bases; the ark and poles and mercy seat; the table and its poles and utensils and bread of the Presence; the lampstand and its accessories and oil; the altar of incense and its poles; the anointing oil and fragrant incense; the screen for the entrance of the tent; the altar of burnt offering; the court and its equipment; the basin. The comprehensive scope of the tabernacle project is laid before the community: this is what their freewill offering will build.</p>",
        "10": "<p><em>wĕkōl-ḥăkam-lēb bākem yābōʾû wĕyaʿăśû ʾēt kol-ʾăšer ṣiwwāh YHWH</em>: repeated call to skilled craftspeople. The repetition of the call emphasizes that the tabernacle requires both the generous givers and the skilled makers — both are acts of covenant service. The theological connection: spiritual gift and material offering are both responses to YHWH's grace.</p>",
        "11": "<p>The construction items: the tabernacle, its tent and covering, its clasps and frames, its bars, pillars, and bases. The technical vocabulary of construction begins here — the terms for the structural elements of the tabernacle will be repeated through chapters 36-40 as their execution is narrated. The repetition (instructions in 25-31, execution in 35-40) embodies the principle that obedient construction follows the divine pattern exactly.</p>",
        "12": "<p>The ark with its poles, the mercy seat, and the veil of the screen — the innermost furnishings of the most holy place. The mercy seat (<em>kappōret</em>) is mentioned first in this recapitulation because it is YHWH's throne, the locus of his presence, the theological center of the entire structure. The veil (<em>pārōket</em>) that separates the holy place from the most holy place is the structural boundary between accessible holiness and the unmediated divine presence.</p>",
        "13": "<p>The table with its poles, all its utensils, and the bread of the Presence (<em>leḥem happānîm</em>, literally 'bread of faces' or 'bread of the presence'). The twelve loaves placed on the table every Sabbath (Lev 24:5-9) represent Israel's twelve tribes perpetually before YHWH's face. The bread of the presence is the enacted sign of Israel's covenant standing: YHWH hosts Israel at his table, sustaining the relationship through continuous provision.</p>",
        "14": "<p>The lampstand for light with its accessories and oil for the light. The <em>mĕnôrāh</em> (lampstand) with its seven branches — already specified in Exod 25:31-40 — is described as providing <em>hammāʾôr</em> (the light). The light of the lampstand in the holy place is the continuous illumination of YHWH's presence — not sunlight but the sanctuary's own light, symbolizing the light of divine revelation in the midst of the community.</p>",
        "15": "<p>The altar of incense with its poles, the anointing oil, the fragrant incense, and the screen for the entrance of the tent. The altar of incense (<em>mizbaḥ hamiqṭār</em>) is the innermost accessible altar — standing before the veil to the most holy place. The incense offering represents prayer ascending to YHWH (Ps 141:2: 'let my prayer be counted as incense before you'). The screen (<em>māsāk</em>) for the entrance separates the holy place from the outer court.</p>",
        "16": "<p>The altar of burnt offering with its bronze grating, its poles, and all its utensils; the basin and its stand. The two altars — burnt offering (in the outer court) and incense (in the holy place) — frame the approach to YHWH's presence: first the sacrifice (burnt offering for atonement), then the worship (incense for prayer). The architectural movement inward through the tabernacle is a movement through purification toward intimacy.</p>",
        "17": "<p>The hangings of the court, its pillars, their bases, and the screen for the gate of the court — the outer boundary of the sacred space. The court's enclosure defined the perimeter of holiness in the wilderness camp. The gate screen (<em>māsāk</em>) marks the threshold between the camp (ordinary space) and the court (sacred space). The graduated holiness — court, holy place, most holy place — reflects the graduated access to YHWH: all Israel, priests, and high priest once a year.</p>",
        "18": "<p>The pegs of the tabernacle and the pegs of the court with their cords. The tent pegs (<em>yĕtēdōt</em>) and cords secure the tabernacle to the ground — the practical anchoring of the divine dwelling in the physical world. The detail is not peripheral: the tabernacle's portability (it can be dismantled and reassembled) is part of its theology — YHWH accompanies his people in their journey, not residing in a fixed location until the land is given.</p>",
        "19": "<p><em>ûgĕdê haśśĕrād laśśārēt baqōdeš bigdê haqqōdeš lĕʾahărōn hakkōhēn ûbigdê bānāyw lĕkahēn</em>: 'the finely worked garments for ministering in the holy place, the holy garments for Aaron the priest, and the garments of his sons, for their service as priests.' The priestly vestments (<em>bigdê šĕrād</em>) are included in the list of items to be provided — the clothing of the mediator is as much a covenant object as the ark or altar. The vestments make the priest who he is in the sanctuary context; they are not mere uniforms but covenantal costume.</p>",
        "20": "<p><em>wayyēṣĕʾû kol-ʿădat bĕnê yiśrāʾēl millipnê mōšeh</em>: 'the whole congregation of the children of Israel departed from Moses's presence.' The assembly disperses to respond individually and communally. The transition from public hearing to private response — from the congregation before Moses to the families at their tents — sets up the extraordinary outpouring of generosity narrated in vv.21-29.</p>",
        "21": "<p><em>wayyābōʾû kol-ʾîš ʾăšer-nĕśāʾô libbô wĕkōl ʾăšer nādĕbāh rûḥô</em>: 'every man whose heart was lifted up came, and everyone whose spirit moved him.' The two expressions of motivation: <em>nāśāʾ lēb</em> (heart lifted up = motivated, enthusiastic) and <em>nādĕbāh rûḥô</em> (spirit moved = spontaneously generous). Both are interior movements, not external pressure. The offering for the tabernacle is the community's freewill response to YHWH's grace. The language anticipates Ezra 1:5 (the returning exiles whose spirits God stirred to rebuild the temple).</p>",
        "22": "<p><em>wayyābōʾû hāʾănāšîm ʿal-hannāšîm kōl nĕdîb lēb</em>: 'both men and women came; all who were of a willing heart brought.' The inclusion of women as full participants in the offering is notable. The ornaments they bring — clasps, earrings, rings, and pendants, all objects of gold — are the personal jewelry of Egyptian origin (12:35-36). The same ornaments stripped off in penitence after the golden calf (33:6) are now given for the tabernacle. The redirected wealth of Egypt funds the dwelling of YHWH.</p>",
        "23": "<p><em>wĕkōl ʾîš ʾăšer nimṣāʾ ʾittô tĕkēlet wĕʾargāmān wĕtôlaʿat šānî ûšēš wĕʿizzîm ûʿōrōt ʾēlîm mĕʾoddāmîm wĕʿōrōt tĕḥāšîm ḥēbîʾû</em>: the materials list continues with textiles and hides. The variety of contributors — those who had blue, purple, scarlet, linen, goats' hair, dyed ram skins, sea cow hides — suggests that the community's diverse wealth was comprehensively mobilized. No single type of material came from one source; the tabernacle is a collective offering.</p>",
        "24": "<p><em>kōl-mārîm tĕrûmat kesep ûnĕḥōšet ḥēbîʾû ʾēt tĕrûmat YHWH</em>: 'everyone who made an offering of silver or bronze brought the LORD's contribution.' The silver and bronze offerings — the metals of the court furnishings and altar — come from those who happened to have them. The word <em>mārîm</em> (lifting up/contributing) is the verbal form of <em>tĕrûmāh</em>. Those who had acacia wood contributed it. The matching of resources to need is YHWH's provision through the community's diverse holdings.</p>",
        "25": "<p><em>wĕkōl-ʾiššāh ḥăkmat-lēb bĕyādêhā ṭāwû wayyābîʾû maṭweh ʾet-hattĕkēlet wĕʾet-hāʾargāmān ʾet-tôlaʿat haššānî wĕʾet-haššēš</em>: 'all the women who were skillful of heart spun with their hands, and they brought what they had spun in blue, purple, and scarlet yarns and fine linen.' The skill-and-spirit combination appears in the women's spinning as well as the men's craftsmanship: <em>ḥăkmat-lēb</em> (skillful/wise of heart) is the quality of both Bezalel (v.31) and the spinning women. Wisdom and skill are not merely technical — they involve the heart's formation and disposition.</p>",
        "26": "<p><em>wĕkōl-hannāšîm ʾăšer nāśāʾ libbān ʾōtānāh bĕḥokmāh ṭāwû ʾet-hāʿizzîm</em>: 'all the women whose hearts moved them with skill spun the goats' hair.' The goats' hair spinning is distinguished — it is a separate group of women whose hearts moved them with this specific skill. The precision of the distinction shows the narrator attending to the specific contributions of specific groups: not all the women did the same thing; each contributed what she was skilled to give. The community's diverse gifts are all needed and all honored.</p>",
        "27": "<p>The leaders (<em>wĕhannĕśîʾîm</em>) brought the onyx stones and the stones for setting in the ephod and breastpiece, and the spices and oil for the lamp, anointing oil, and fragrant incense. The leaders' distinctive contribution is the most valuable materials — the gems and spices that required wealth to obtain. Leadership is expressed here in generous material provision for the community's worship. The leaders' gift completes the comprehensive offering: precious stones and spices that no ordinary member could provide.</p>",
        "28": "<p><em>wĕhabbĕśem wĕhašāmen lĕmāʾôr ûlĕšemen hammišḥāh ûliqṭōret hassammîm</em>: 'and the spice and the oil for the light, for the anointing oil, and for the fragrant incense.' The three specialized uses of oil and spice — lamp oil, anointing oil, incense — require different preparations. The leaders' provision of the raw materials enables the skilled craftsmen to prepare the specific formulations. The community's generosity covers both the materials and the expertise needed to use them correctly.</p>",
        "29": "<p><em>kōl-ʾîš wĕʾiššāh ʾăšer nādab libbām ʾōtām lĕhābîʾ lĕkol-hamĕlāʾkāh ʾăšer ṣiwwāh YHWH laʿăśôt bĕyad mōšeh ḥēbîʾû bĕnê yiśrāʾēl nĕdābāh laYHWH</em>: 'all men and women, the people of Israel, whose heart moved them to bring anything for the work that YHWH had commanded by Moses to be done brought it as a freewill offering to YHWH.' The summary of the offering: the whole community (<em>kol-ʾîš wĕʾiššāh</em>), motivated internally (<em>nādab libbām</em>), brought their contributions as a freewill offering (<em>nĕdābāh</em>) to YHWH. The word <em>nĕdābāh</em> (freewill offering, voluntary gift) is the technical term for an offering given without obligation — here applied to the entire tabernacle construction fund.</p>",
        "30": "<p><em>rĕʾû qārāʾ YHWH bĕšēm bĕṣalʾēl ben-ûrî ben-ḥûr lĕmaṭṭēh yĕhûdāh</em>: 'See, YHWH has called by name Bezalel the son of Uri, son of Hur, of the tribe of Judah.' The divine calling by name — <em>qārāʾ bĕšēm</em> — is the language of prophetic appointment (Isa 45:4: 'I call you by your name'). Bezalel's genealogy — son of Uri, son of Hur, of the tribe of Judah — connects him to the leadership present at the Sinai events (Hur stood beside Aaron holding Moses's arms, 17:12). The appointment of the craftsman is as much a divine calling as the appointment of a prophet.</p>",
        "31": "<p><em>waymallēʾ ʾōtô rûaḥ ʾĕlōhîm bĕḥokmāh bîtĕbûnāh ûbĕdaʿat ûbĕkōl mĕlāʾkāh</em>: 'and he has filled him with the Spirit of God, with wisdom, understanding, and knowledge, and with all craftsmanship.' This is the first explicit charismatic endowment in Scripture — the Spirit of God filling a person for a specific task. The three gifts: <em>ḥokmāh</em> (wisdom — practical skill and discernment), <em>tĕbûnāh</em> (understanding — analytic insight), <em>daʿat</em> (knowledge — experiential and technical know-how). The same triad appears in Prov 3:19-20: 'YHWH by wisdom founded the earth, by understanding established the heavens; by his knowledge the deeps broke open.' The craftsman shares in the wisdom by which the world was made.</p>",
        "32": "<p><em>ûlĕḥašōb maḥăšābōt laʿăśôt bazzāhāb ûbakkesep ûbannĕḥōšet</em>: 'to devise artistic designs, to work in gold, silver, and bronze.' The verb <em>ḥāšab</em> (to think/devise/plan) is the same root as the <em>ḥōšēb</em> craftsman whose intricate work is required for the tabernacle. Artistic design is a form of thought — <em>ḥăšōb maḥăšābōt</em> (thinking of thoughts) — and the craftsman's mind engaged in design participates in the same faculty that YHWH used in creation. Beauty is an intellectual as well as a manual achievement.</p>",
        "33": "<p><em>ûbĕḥărōšet ʾeben lĕmallōʾt ûbĕḥărōšet ʿēṣ laʿăśôt bĕkōl mĕleʾket maḥăšābet</em>: 'in cutting stones for setting, and in carving wood, for work in every skilled craft.' The full range of Bezalel's mandate: gem-cutting, wood-carving, and every kind of skilled work. The Hebrew <em>ḥărōšet</em> (craftsmanship, artisanship) from <em>ḥāraš</em> (craftsman) covers the full range of skilled trades. The tabernacle requires all of them — there is no hierarchy among the crafts, only the coordinating direction of the Spirit-filled master craftsman.</p>",
        "34": "<p><em>ûlĕhôrōt nātan bĕlibbô hûʾ wĕʾohŏlîʾāb ben-ʾăḥîsāmāk lĕmaṭṭēh dān</em>: 'and he has given him the ability to teach, both him and Oholiab the son of Ahisamach of the tribe of Dan.' The gift of teaching (<em>lĕhôrōt</em> — from the same root as <em>tôrāh</em>) is included among Bezalel's endowments. The Spirit-filled craftsman is also a teacher — the wisdom given to him is transmissible. Oholiab is introduced as the second master craftsman: from the tribe of Dan (north), pairing with Bezalel from Judah (south) — the collaboration of the two major tribes in building YHWH's dwelling.</p>",
        "35": "<p><em>mallēʾ ʾōtām ḥokmat-lēb laʿăśôt kōl-mĕleʾket ḥārāš wĕḥōšēb ûrōqēm bĕttĕkēlet ûbāʾargāmān bĕtôlaʿat haššānî ûbāššēš wĕʾōrēg ʿōśēh kōl-mĕlāʾkāh wĕḥōšĕbê maḥăšābōt</em>: 'He has filled them with skill to do every sort of work done by an engraver or by a designer or by an embroiderer in blue and purple and scarlet yarns and fine twined linen, or by a weaver — by any sort of workman or skilled designer.' The comprehensive list of craft categories closes with the summary <em>ḥōšĕbê maḥăšābōt</em> (devisers of designs/skilled thinkers). The breadth of Spirit-given skills encompasses every art required for the tabernacle: engraving, designing, embroidering, weaving. The Spirit of God equips the whole spectrum of human artistic capacity in service of the covenant dwelling.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'exodus')
    merge_comm(existing, EXODUS_ORIGINAL)
    save_comm('mkt-original', 'exodus', existing)
    for ch in ['33', '34', '35']:
        vv = existing.get(ch, {})
        print(f'  ch{ch}: {len(vv)} verse(s) with original commentary')

if __name__ == '__main__':
    main()
